import{_ as l,C as s,o as e,c as d,a5 as A,b as o,w as t,a,E as r,a4 as n}from"./chunks/framework.gGRxziV4.js";const c=JSON.parse('{"title":"三大支柱","description":"","frontmatter":{},"headers":[],"relativePath":"02-上下文工程/02-三大支柱.md","filePath":"02-上下文工程/02-三大支柱.md","lastUpdated":1774181700000}'),p={name:"02-上下文工程/02-三大支柱.md"};function i(C,E,h,g,F,_){const B=s("Mermaid");return e(),d("div",null,[E[2]||(E[2]=A('<h1 id="三大支柱" tabindex="-1">三大支柱 <a class="header-anchor" href="#三大支柱" aria-label="Permalink to &quot;三大支柱&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 2 模块的第 2 章。</p></blockquote><p>业界顶尖团队正在趋同于一套上下文工程架构：极简的原子函数调用层 + 庞大的可供探索的外部文件系统与脚本库。这是整个行业为平衡无限的能力拓展与有限的上下文窗口，共同演进而来的最优解。</p><hr><h2 id="核心矛盾" tabindex="-1">核心矛盾 <a class="header-anchor" href="#核心矛盾" aria-label="Permalink to &quot;核心矛盾&quot;">​</a></h2><p>Agent 的本质是在循环中调用工具的大语言模型。这个简单的循环在长任务时带来巨大挑战——上下文爆炸。Menlo 提到一个典型任务平均需要 50 次工具调用，Anthropic 佐证生产级 Agent 对话轮次可能长达数百轮。</p><p>这意味着模型在每一步决策时都要背负之前所有轮次的工具结果，不仅导致成本和延迟急剧膨胀，更致命地引发上下文腐烂。</p><p>核心矛盾：Agent 任务天然会产生巨量上下文，但模型在巨量上下文下性能会下降。</p><p>上下文工程就是这门精巧的艺术和科学——用恰到好处、下一步所需的正确信息填充上下文窗口。它被提炼为三个核心支柱：</p>',9)),(e(),o(n,null,{default:t(()=>[r(B,{id:"mermaid-27",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E6%A0%B8%E5%BF%83%E7%9F%9B%E7%9B%BE%3Cbr%2F%3E%E4%BB%BB%E5%8A%A1%E4%BA%A7%E7%94%9F%E5%B7%A8%E9%87%8F%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3E%E4%BD%86%E6%A8%A1%E5%9E%8B%E6%80%A7%E8%83%BD%E9%9A%8F%E4%B8%8A%E4%B8%8B%E6%96%87%E5%A2%9E%E5%8A%A0%E8%80%8C%E4%B8%8B%E9%99%8D%5D%20--%3E%20B%5B%E5%8D%B8%E8%BD%BD%20Offloading%5D%0A%20%20%20%20A%20--%3E%20C%5B%E7%BC%A9%E5%87%8F%20Reduction%5D%0A%20%20%20%20A%20--%3E%20D%5B%E9%9A%94%E7%A6%BB%20Isolation%5D%0A%20%20%20%20B%20--%3E%20E%5B%E6%96%87%E4%BB%B6%E7%B3%BB%E7%BB%9F%E5%8D%B3%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3E%E5%88%86%E5%B1%82%E8%A1%8C%E5%8A%A8%E7%A9%BA%E9%97%B4%3Cbr%2F%3E%E6%B8%90%E8%BF%9B%E5%BC%8F%E6%8A%AB%E9%9C%B2%5D%0A%20%20%20%20C%20--%3E%20F%5B%E5%8F%AF%E9%80%86%E5%8E%8B%E7%BC%A9%2F%E6%8C%87%E9%92%88%E6%9B%BF%E4%BB%A3%3Cbr%2F%3E%E4%B8%8D%E5%8F%AF%E9%80%86%E6%91%98%E8%A6%81%2F%E6%9C%80%E5%90%8E%E6%89%8B%E6%AE%B5%5D%0A%20%20%20%20D%20--%3E%20G%5B%E9%80%9A%E4%BF%A1%E6%A8%A1%E5%BC%8F%2F%E4%BD%8E%E6%88%90%E6%9C%AC%3Cbr%2F%3E%E5%85%B1%E4%BA%AB%E4%B8%8A%E4%B8%8B%E6%96%87%2F%E5%85%A8%E8%A7%86%E9%87%8E%5D%0A%20%20%20%20E%20--%3E%20H%5B%E6%9E%81%E7%AE%80%E5%8E%9F%E5%AD%90%E5%87%BD%E6%95%B0%E5%B1%82%3Cbr%2F%3E%2B%20%E5%BA%9E%E5%A4%A7%E5%A4%96%E9%83%A8%E6%96%87%E4%BB%B6%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20F%20--%3E%20H%0A%20%20%20%20G%20--%3E%20H%0A"})]),fallback:t(()=>[...E[0]||(E[0]=[a(" Loading... ",-1)])]),_:1})),E[3]||(E[3]=A('<blockquote><p>💡 <strong>图解：</strong> 三大支柱的共同目标是让模型在每一步只看它需要的东西——多一点是噪音，少一点是盲区。</p></blockquote><table tabindex="0"><thead><tr><th>支柱</th><th>核心思想</th></tr></thead><tbody><tr><td><strong>卸载（Offloading）</strong></td><td>将上下文从 LLM 窗口转移到外部存储，以便后续选择性检索</td></tr><tr><td><strong>缩减（Reduction）</strong></td><td>减小每步传递给模型的上下文大小</td></tr><tr><td><strong>隔离（Isolation）</strong></td><td>为不同独立任务使用单独的上下文窗口</td></tr></tbody></table><hr><h2 id="支柱一-卸载" tabindex="-1">支柱一：卸载 <a class="header-anchor" href="#支柱一-卸载" aria-label="Permalink to &quot;支柱一：卸载&quot;">​</a></h2><p>卸载已从卸载数据进化到卸载工具。</p><p><strong>卸载数据</strong>：赋予 Agent 文件系统，使其能在长任务中保存和回忆信息。Anthropic 的多 Agent 研究中，Agent 会将计划写入文件，执行完子任务后再读回计划确保不偏离目标。Claude Code 的 <code>.claude.md</code> 文件允许 Agent 在多次调用间持久化存储用户偏好。</p><p><strong>卸载工具——分层行动空间</strong>：若有 100 个工具都塞进 Prompt，会导致模型混淆和 Prompt 膨胀。Menlo 的解决方案是保持函数调用层极简，只保留少数原子工具（bash 和文件操作），将绝大多数动作卸载为文件系统中的脚本。</p><p>顶级 Agent 的原生工具集都极少：Claude Code 约 12 个，Menlo 不到 20 个，Deep Agents 仅 11 个。</p><p><strong>最终演进——渐进式披露</strong>：连脚本也不必一开始就全部告知模型。Agent 启动时仅加载每个 Skill 的标题，决定使用某技能时才完整读取。Agent 通过 bash 工具在庞大脚本目录中自主寻找和阅读说明书。</p><h3 id="三层行动空间" tabindex="-1">三层行动空间 <a class="header-anchor" href="#三层行动空间" aria-label="Permalink to &quot;三层行动空间&quot;">​</a></h3><p>Menlo 设计了由内到外的三个层次：</p><p><strong>第一层：函数调用（原子操作）</strong>——与模型直接交互的唯一一层，极少数固定不变的原子函数。用灵活性换取可靠性与高性能，模式安全、缓存友好。</p><p><strong>第二层：沙盒使用程序（命令行）</strong>——Agent 通过 <code>execute_shell</code> 运行预装工具。模型被教会如何去发现和学习：引导提示告知工具目录、主动执行 <code>ls</code> 查看可用工具、执行 <code>--help</code> 学习用法。适合处理可以稍等一下的复杂离线任务。</p><p><strong>第三层：包和 API（编写代码）</strong>——最开放、能力最强。Agent 编写并执行 Python 脚本调用任意 API。取决于能力缺口——一二层现成工具无法完成任务时才做出&quot;我需要编写代码&quot;的决策。</p><p>从模型视角看，它完全不知道有三层的存在，最终都只需要调用第一层的几个原子函数。接口简洁、缓存友好、正交设计。</p>',15)),(e(),o(n,null,{default:t(()=>[r(B,{id:"mermaid-108",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%E6%A8%A1%E5%9E%8B%E8%A7%86%E8%A7%92%5D%20--%3E%7C%E5%94%AF%E4%B8%80%E7%9A%84%E6%8E%A5%E5%8F%A3%7C%20B%5B%E7%AC%AC%E4%B8%80%E5%B1%82%3A%20%E5%87%BD%E6%95%B0%E8%B0%83%E7%94%A8%3Cbr%2F%3E%E5%B0%91%E6%95%B0%E5%8E%9F%E5%AD%90%E6%93%8D%E4%BD%9C%5D%0A%20%20%20%20B%20--%3E%20C%5B%E7%AC%AC%E4%BA%8C%E5%B1%82%3A%20%E6%B2%99%E7%9B%92%E4%BD%BF%E7%94%A8%E7%A8%8B%E5%BA%8F%3Cbr%2F%3Eexecute_shell%20%E8%BF%90%E8%A1%8C%E9%A2%84%E8%A3%85%E5%B7%A5%E5%85%B7%5D%0A%20%20%20%20C%20--%3E%20D%5B%E7%AC%AC%E4%B8%89%E5%B1%82%3A%20%E5%8C%85%E5%92%8C%20API%3Cbr%2F%3EAgent%20%E7%BC%96%E5%86%99%20Python%20%E8%84%9A%E6%9C%AC%5D%0A%20%20%20%20B%20--%3E%7C%E6%9E%81%E7%AE%80%E5%9B%BA%E5%AE%9A%3Cbr%2F%3E%E6%A8%A1%E5%BC%8F%E5%AE%89%E5%85%A8%7C%20E%5B%E5%8F%AF%E9%9D%A0%2B%E7%BC%93%E5%AD%98%E5%8F%8B%E5%A5%BD%5D%0A%20%20%20%20C%20--%3E%7C%E6%8C%89%E9%9C%80%E5%8F%91%E7%8E%B0%3Cbr%2F%3E%E8%87%AA%E4%B8%BB%E5%AD%A6%E4%B9%A0%7C%20F%5B%E7%81%B5%E6%B4%BB%2B%E5%8F%AF%E6%89%A9%E5%B1%95%5D%0A%20%20%20%20D%20--%3E%7C%E8%83%BD%E5%8A%9B%E7%BC%BA%E5%8F%A3%E6%97%B6%3Cbr%2F%3E%E6%89%8D%E8%A7%A6%E5%8F%91%7C%20G%5B%E5%BC%80%E6%94%BE%2B%E6%9C%80%E5%BC%BA%E8%83%BD%E5%8A%9B%5D%0A"})]),fallback:t(()=>[...E[1]||(E[1]=[a(" Loading... ",-1)])]),_:1})),E[4]||(E[4]=A('<blockquote><p>💡 <strong>图解：</strong> 三层行动空间对模型完全透明——它只看到几个原子函数，但通过它们能撬动整个工具世界。</p></blockquote><hr><h2 id="支柱二-缩减" tabindex="-1">支柱二：缩减 <a class="header-anchor" href="#支柱二-缩减" aria-label="Permalink to &quot;支柱二：缩减&quot;">​</a></h2><p><strong>压缩（Compression）</strong>——可逆操作。当工具结果变得陈旧时，将完整内容卸载到文件，再在消息历史中用指向该文件的指针替换。Agent 未来仍可 100% 恢复原始信息。</p><p>压缩 ≠ 摘要。压缩是可逆无损的外部化操作，用轻量级指针替代。摘要是有损不可逆操作，只有当压缩收益非常小时才作为最后手段启用。</p><p>执行策略：先反复压缩，压缩收益变小后再用摘要。摘要前先卸载完整上下文到日志文件（买保险）。只压缩旧 50%，保留最新几个完整工具调用作为 Few-shot 示例校准模型行为。摘要必须基于完整版本，不能基于已压缩数据。</p><p>定义浅腐烂阈值（128K-200K Token）作为触发器，达到时优先压缩，接近极限时才启用摘要。</p><hr><h2 id="支柱三-隔离" tabindex="-1">支柱三：隔离 <a class="header-anchor" href="#支柱三-隔离" aria-label="Permalink to &quot;支柱三：隔离&quot;">​</a></h2><p><strong>通过通信</strong>：主 Agent 给子 Agent 传递简短指令，子 Agent 在隔离干净的上下文中完成任务，仅返回最终结果。成本低、延迟低、KV 缓存友好。适合可清晰切分的简单任务。</p><p><strong>通过共享上下文</strong>：子 Agent 被允许访问主 Agent 的完整上下文历史，但在新的 System Prompt 下行动。收益是完整历史视野能处理复杂任务，代价是 KV 缓存完全失效，必须支付全价预填充成本。</p><hr><h2 id="业界共识" tabindex="-1">业界共识 <a class="header-anchor" href="#业界共识" aria-label="Permalink to &quot;业界共识&quot;">​</a></h2><p>所有顶级生产级 Agent 都在趋同于一套共同的、经实战检验的架构：一个极简的原子函数调用层 + 一个庞大的可供探索的外部文件系统与脚本库。上下文工程从零散技巧提升为完整严谨的系统设计哲学。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>卸载：文件系统即上下文、分层行动空间、渐进式披露</li><li>缩减：可逆压缩（指针替代）vs 不可逆摘要（最后手段）</li><li>隔离：通信模式（低成本）vs 共享上下文模式（高代价全视野）</li><li>最终公式：极简原子函数层 + 庞大外部文件系统 = 生产级 Agent 架构</li></ul><hr><p><strong>上一章</strong>: <a href="./01-上下文的诅咒.html">上下文的诅咒</a> | <strong>下一章</strong>: <a href="./03-动态上下文与实战.html">动态上下文与实战</a></p>',19))])}const b=l(p,[["render",i]]);export{c as __pageData,b as default};
